def range_summary(nums):
    if not nums:
        return ''
    runs = []
    current, length = nums[0], 1
    for n in nums[1:]:
        if n == current + 1:
            length += 1
        else:
            runs.append((current, current + length))
            current, length = n, 1
    runs.append((current, current + length))
    return ', '.join('-'.join(map(str, r)) if len(r) > 1 else str(r[0]) for r in runs)
